<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">	PCON</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">00</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
